ALTER TABLE customer_preferences ADD COLUMN IF NOT EXISTS browse_context TEXT;
ALTER TABLE inventory ADD COLUMN IF NOT EXISTS category_tag VARCHAR(50) DEFAULT 'general';
UPDATE inventory SET category_tag = CASE WHEN item_name ILIKE ANY(ARRAY['%milk%','%butter%','%ghee%','%curd%','%paneer%','%egg%','%bread%']) THEN 'daily_essentials' WHEN item_name ILIKE ANY(ARRAY['%tomato%','%onion%','%potato%','%carrot%','%cabbage%','%spinach%','%banana%','%apple%','%mango%']) THEN 'vegetables_fruits' WHEN item_name ILIKE ANY(ARRAY['%rice%','%wheat%','%flour%','%oil%','%dal%','%lentil%','%sugar%','%salt%']) THEN 'grains_oils' WHEN item_name ILIKE ANY(ARRAY['%chips%','%biscuit%','%juice%','%water%','%soda%','%cola%','%snack%']) THEN 'snacks_drinks' ELSE 'general' END WHERE category_tag IS NULL OR category_tag = 'general';
